export const BASH = `# shogo shell integration — bash
#
# Sourced from a temporary --rcfile. The wrapper rcfile is responsible
# for sourcing the user's own ~/.bashrc / ~/.bash_profile BEFORE this
# file, so our hooks are layered on top of (not in place of) the user's
# setup. NEVER replace PROMPT_COMMAND — only append.
#
# Emits the VS Code OSC 633 marks. We use the bash-preexec.sh idiom
# (DEBUG trap guarded by BASH_COMMAND != PROMPT_COMMAND) so we run
# before each command and not on every sub-command of PROMPT_COMMAND.

# Bail out if the user opted out, or if we've already been sourced.
if [ "\${SHOGO_DISABLE_SHELL_INTEGRATION:-0}" = "1" ]; then return 0; fi
if [ "\${__shogo_integration_loaded:-0}" = "1" ]; then return 0; fi
__shogo_integration_loaded=1

# OSC 633 helpers. Use BEL terminator; bash's PROMPT_COMMAND printf is
# happy with \\a and most readline integrations also are.
__shogo_osc() { printf '\\033]633;%s\\007' "$1"; }
__shogo_prompt_start() { __shogo_osc 'A'; }
__shogo_prompt_end()   { __shogo_osc 'B'; }
__shogo_pre_exec()     { __shogo_osc 'C'; }
__shogo_post_exec()    { __shogo_osc "D;$1"; }
__shogo_cwd()          { __shogo_osc "P;Cwd=$PWD"; }

# Guard for the DEBUG trap — only fire on real user commands.
__shogo_preexec_invoked=0
__shogo_preexec() {
    # Don't fire on the PROMPT_COMMAND chain itself.
    if [ -n "\${COMP_LINE:-}" ]; then return 0; fi
    if [ "$BASH_COMMAND" = "\${PROMPT_COMMAND:-}" ]; then return 0; fi
    if [ "$__shogo_preexec_invoked" = "1" ]; then return 0; fi
    __shogo_preexec_invoked=1
    __shogo_pre_exec
}

# Runs after every command; PS0-equivalent for the pre-exec mark is
# the DEBUG trap above.
__shogo_postexec() {
    local exit=$?
    __shogo_post_exec "$exit"
    __shogo_preexec_invoked=0
    __shogo_cwd
    __shogo_prompt_start
    return $exit
}

trap '__shogo_preexec' DEBUG

# Append (never replace) PROMPT_COMMAND. Bash 5.1+ supports an array;
# fall back to the string form for older versions.
if [ -n "\${BASH_VERSINFO:-}" ] && [ "\${BASH_VERSINFO[0]}" -ge 5 ] \\
   && [ "\${BASH_VERSINFO[1]}" -ge 1 ]; then
    PROMPT_COMMAND=("__shogo_postexec" "\${PROMPT_COMMAND[@]:-}")
else
    if [ -z "\${PROMPT_COMMAND:-}" ]; then
        PROMPT_COMMAND='__shogo_postexec'
    else
        # Avoid double-prepending if we somehow get sourced twice.
        case ";$PROMPT_COMMAND;" in
            *";__shogo_postexec;"*) ;;
            *) PROMPT_COMMAND="__shogo_postexec;\${PROMPT_COMMAND}" ;;
        esac
    fi
fi

# Append the prompt-end (B) mark to PS1 so it fires AFTER the user's
# prompt characters draw. OSC 633 contract is A …user prompt… B. The
# \\[…\\] wrapper tells readline those bytes are zero-width so prompt
# alignment stays correct.
__shogo_PS1_orig="$PS1"
PS1="\${PS1}\\[$(__shogo_prompt_end)\\]"

# First-time announce: emit a Cwd and an initial prompt-start so the
# tracker has an anchor before the very first command runs.
__shogo_cwd
__shogo_prompt_start
`

export const ZSH_ENV = `# shogo shell integration — zsh .zshenv
#
# zsh sources .zshenv on EVERY invocation (interactive, non-interactive,
# login, sub-shells). Our job here is exactly one thing: source the user's
# own .zshenv from their ORIGINAL ZDOTDIR if it exists.
#
# CRITICAL: we must NOT mutate ZDOTDIR. If we did, zsh's next step
# ("source $ZDOTDIR/.zshrc") would read the user's .zshrc and entirely
# skip ours — no hooks would be installed and the terminal would show
# no OSC 633 marks. ZDOTDIR stays pointed at our temp dir for the
# duration of zsh startup; our .zshrc takes care of sourcing the user's
# .zshrc explicitly.
#
# We deliberately do NOT install any hooks here — those go in .zshrc
# (interactive only) so non-interactive sub-shells stay clean.

_SHOGO_USER_ZDOTDIR="\${_SHOGO_ORIG_ZDOTDIR:-$HOME}"

if [ -r "$_SHOGO_USER_ZDOTDIR/.zshenv" ]; then
    . "$_SHOGO_USER_ZDOTDIR/.zshenv"
fi
`

export const ZSH_PROFILE = `# shogo shell integration — zsh .zprofile (login shells only)
# Sourced for login shells before .zshrc. Pass through to the user's.

if [ -r "\${_SHOGO_ORIG_ZDOTDIR:-$HOME}/.zprofile" ]; then
    . "\${_SHOGO_ORIG_ZDOTDIR:-$HOME}/.zprofile"
fi
`

export const ZSH_RC = `# shogo shell integration — zsh .zshrc (interactive shells)
#
# Sources the user's .zshrc FIRST, then installs the OSC 633 hooks
# on top. Order matters: if we hooked first, the user's prompt
# customisations would clobber our PS1 wrapper.

if [ -r "\${_SHOGO_ORIG_ZDOTDIR:-$HOME}/.zshrc" ]; then
    . "\${_SHOGO_ORIG_ZDOTDIR:-$HOME}/.zshrc"
fi

# Opt-out and double-load guards.
[ "\${SHOGO_DISABLE_SHELL_INTEGRATION:-0}" = "1" ] && return 0
[ "\${__shogo_integration_loaded:-0}" = "1" ] && return 0
__shogo_integration_loaded=1

__shogo_osc()          { printf '\\033]633;%s\\007' "$1" }
__shogo_prompt_start() { __shogo_osc 'A' }
__shogo_prompt_end()   { __shogo_osc 'B' }
__shogo_pre_exec()     { __shogo_osc 'C' }
__shogo_post_exec()    { __shogo_osc "D;$1" }
__shogo_cwd()          { __shogo_osc "P;Cwd=$PWD" }

# zsh has first-class preexec/precmd hooks; no DEBUG-trap gymnastics needed.
autoload -Uz add-zsh-hook

__shogo_preexec_hook() {
    # $1 is the command line about to run. We could emit it as OSC 633 E
    # for "command line" but VS Code's tracker reconstructs E from the
    # readline buffer anyway, so we stick to C (pre-exec) for now.
    __shogo_pre_exec
}

__shogo_precmd_hook() {
    local exit=$?
    __shogo_post_exec "$exit"
    __shogo_cwd
    __shogo_prompt_start
    return $exit
}

add-zsh-hook preexec __shogo_preexec_hook
add-zsh-hook precmd  __shogo_precmd_hook

# Wrap the user's PS1 so we emit the prompt-end (B) mark IMMEDIATELY AFTER
# the user's prompt characters finish drawing. The OSC 633 contract is
# A …user prompt… B, so B goes at the END of PS1. The %{...%} wrapper
# tells zsh those bytes are zero-width so prompt alignment stays correct.
PS1="\${PS1}%{$(__shogo_prompt_end)%}"

# Initial Cwd + A so the tracker has an anchor for the very first prompt.
__shogo_cwd
__shogo_prompt_start
`

